package com.example.samlsp.security;

import com.example.samlsp.config.SamlSpProperties;
import org.opensaml.security.credential.Credential;
import org.opensaml.security.x509.BasicX509Credential;
import org.springframework.core.io.ResourceLoader;
import org.springframework.stereotype.Component;

import javax.annotation.PostConstruct;
import java.io.InputStream;
import java.security.KeyStore;
import java.security.PrivateKey;
import java.security.cert.CertificateFactory;
import java.security.cert.X509Certificate;

@Component
public class CredentialManager {

    private final SamlSpProperties properties;
    private final ResourceLoader resourceLoader;
    private BasicX509Credential spCredential;
    private BasicX509Credential idpCredential;

    public CredentialManager(SamlSpProperties properties, ResourceLoader resourceLoader) {
        this.properties = properties;
        this.resourceLoader = resourceLoader;
    }

    @PostConstruct
    public void init() throws Exception {
        loadSpCredential();
        if (properties.getIdpCertificatePath() != null) {
            loadIdpCredential();
        }
    }

    private void loadSpCredential() throws Exception {
        KeyStore keyStore = KeyStore.getInstance("JKS");
        try (InputStream is = resourceLoader.getResource(properties.getKeystorePath()).getInputStream()) {
            keyStore.load(is, properties.getKeystorePassword().toCharArray());
        }

        PrivateKey privateKey = (PrivateKey) keyStore.getKey(
                properties.getKeyAlias(),
                properties.getKeyPassword().toCharArray()
        );
        X509Certificate certificate = (X509Certificate) keyStore.getCertificate(properties.getKeyAlias());

        spCredential = new BasicX509Credential(certificate, privateKey);
        spCredential.setEntityId(properties.getEntityId());
    }

    private void loadIdpCredential() throws Exception {
        try (InputStream is = resourceLoader.getResource(properties.getIdpCertificatePath()).getInputStream()) {
            CertificateFactory cf = CertificateFactory.getInstance("X.509");
            X509Certificate idpCert = (X509Certificate) cf.generateCertificate(is);
            idpCredential = new BasicX509Credential(idpCert);
            idpCredential.setEntityId(properties.getIdpEntityId());
        }
    }

    public BasicX509Credential getSpCredential() {
        return spCredential;
    }

    public Credential getIdpCredential() {
        return idpCredential;
    }

    public X509Certificate getSpCertificate() {
        return spCredential.getEntityCertificate();
    }
}

