import java.util.UUID;

@Component
public class SamlMessageBuilder {

    private final SamlSpProperties properties;
    private final CredentialManager credentialManager;

    public SamlMessageBuilder(SamlSpProperties properties, CredentialManager credentialManager) {
        this.properties = properties;
        this.credentialManager = credentialManager;
    }

    public AuthnRequest buildAuthnRequest() throws MarshallingException, SignatureException, SecurityException {
        AuthnRequest authnRequest = new AuthnRequestBuilder().buildObject();
        authnRequest.setID("_" + UUID.randomUUID().toString());
        authnRequest.setVersion(SAMLVersion.VERSION_20);
        authnRequest.setIssueInstant(DateTime.now());
        authnRequest.setDestination(properties.getIdpSsoUrl());
        authnRequest.setProtocolBinding("urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST");
        authnRequest.setAssertionConsumerServiceURL(properties.getAcsUrl());
        authnRequest.setForceAuthn(false);
        authnRequest.setIsPassive(false);

        Issuer issuer = new IssuerBuilder().buildObject();
        issuer.setValue(properties.getEntityId());
        authnRequest.setIssuer(issuer);

        NameIDPolicy nameIDPolicy = new NameIDPolicyBuilder().buildObject();
        nameIDPolicy.setFormat("urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress");
        nameIDPolicy.setAllowCreate(true);
        authnRequest.setNameIDPolicy(nameIDPolicy);

        RequestedAuthnContext requestedAuthnContext = new RequestedAuthnContextBuilder().buildObject();
        requestedAuthnContext.setComparison(AuthnContextComparisonTypeEnumeration.EXACT);

        AuthnContextClassRef authnContextClassRef = new AuthnContextClassRefBuilder().buildObject();
        authnContextClassRef.setURI("urn:oasis:names:tc:SAML:2.0:ac:classes:PasswordProtectedTransport");
        requestedAuthnContext.getAuthnContextClassRefs().add(authnContextClassRef);
        authnRequest.setRequestedAuthnContext(requestedAuthnContext);

        if (properties.isAuthnRequestsSigned()) {
            signSamlObject(authnRequest);
        }

        return authnRequest;
    }

    public LogoutRequest buildLogoutRequest(String nameId, String sessionIndex) throws MarshallingException, SignatureException, SecurityException {
        LogoutRequest logoutRequest = new LogoutRequestBuilder().buildObject();
        logoutRequest.setID("_" + UUID.randomUUID().toString());
        logoutRequest.setVersion(SAMLVersion.VERSION_20);
        logoutRequest.setIssueInstant(DateTime.now());
        logoutRequest.setDestination(properties.getIdpSloUrl());

        Issuer issuer = new IssuerBuilder().buildObject();
        issuer.setValue(properties.getEntityId());
        logoutRequest.setIssuer(issuer);

        NameID nameID = new NameIDBuilder().buildObject();
        nameID.setFormat("urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress");
        nameID.setValue(nameId);
        logoutRequest.setNameID(nameID);

        if (sessionIndex != null) {
            SessionIndex sessionIdx = new SessionIndexBuilder().buildObject();
            sessionIdx.setValue(sessionIndex);
            logoutRequest.getSessionIndexes().add(sessionIdx);
        }

        signSamlObject(logoutRequest);

        return logoutRequest;
    }

    public LogoutResponse buildLogoutResponse(String inResponseTo) throws MarshallingException, SignatureException, SecurityException {
        LogoutResponse logoutResponse = new LogoutResponseBuilder().buildObject();
        logoutResponse.setID("_" + UUID.randomUUID().toString());
        logoutResponse.setVersion(SAMLVersion.VERSION_20);
        logoutResponse.setIssueInstant(DateTime.now());
        logoutResponse.setDestination(properties.getIdpSloUrl());
        logoutResponse.setInResponseTo(inResponseTo);

        Issuer issuer = new IssuerBuilder().buildObject();
        issuer.setValue(properties.getEntityId());
        logoutResponse.setIssuer(issuer);

        Status status = new StatusBuilder().buildObject();
        StatusCode statusCode = new StatusCodeBuilder().buildObject();
        statusCode.setValue(StatusCode.SUCCESS);
        status.setStatusCode(statusCode);
        logoutResponse.setStatus(status);

        signSamlObject(logoutResponse);

        return logoutResponse;
    }

    public EntityDescriptor buildSpMetadata() throws SecurityException {
        EntityDescriptor entityDescriptor = new EntityDescriptorBuilder().buildObject();
        entityDescriptor.setEntityID(properties.getEntityId());

        SPSSODescriptor spSsoDescriptor = new SPSSODescriptorBuilder().buildObject();
        spSsoDescriptor.setWantAssertionsSigned(properties.isWantAssertionsSigned());
        spSsoDescriptor.setAuthnRequestsSigned(properties.isAuthnRequestsSigned());
        spSsoDescriptor.addSupportedProtocol("urn:oasis:names:tc:SAML:2.0:protocol");

        // Signing Key Descriptor
        KeyDescriptor signingKeyDescriptor = new KeyDescriptorBuilder().buildObject();
        signingKeyDescriptor.setUse(UsageType.SIGNING);

        X509KeyInfoGeneratorFactory keyInfoGeneratorFactory = new X509KeyInfoGeneratorFactory();
        keyInfoGeneratorFactory.setEmitEntityCertificate(true);
        KeyInfoGenerator keyInfoGenerator = keyInfoGeneratorFactory.newInstance();
        signingKeyDescriptor.setKeyInfo(keyInfoGenerator.generate(credentialManager.getSpCredential()));
        spSsoDescriptor.getKeyDescriptors().add(signingKeyDescriptor);

        // Encryption Key Descriptor
        KeyDescriptor encryptionKeyDescriptor = new KeyDescriptorBuilder().buildObject();
        encryptionKeyDescriptor.setUse(UsageType.ENCRYPTION);
        encryptionKeyDescriptor.setKeyInfo(keyInfoGenerator.generate(credentialManager.getSpCredential()));
        spSsoDescriptor.getKeyDescriptors().add(encryptionKeyDescriptor);

        // NameID Formats
        NameIDFormat emailNameIdFormat = new NameIDFormatBuilder().buildObject();
        emailNameIdFormat.setURI("urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress");
        spSsoDescriptor.getNameIDFormats().add(emailNameIdFormat);

        NameIDFormat persistentNameIdFormat = new NameIDFormatBuilder().buildObject();
        persistentNameIdFormat.setURI("urn:oasis:names:tc:SAML:2.0:nameid-format:persistent");
        spSsoDescriptor.getNameIDFormats().add(persistentNameIdFormat);

        // Assertion Consumer Service
        AssertionConsumerService assertionConsumerService = new AssertionConsumerServiceBuilder().buildObject();
        assertionConsumerService.setIndex(0);
        assertionConsumerService.setIsDefault(true);
        assertionConsumerService.setBinding("urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST");
        assertionConsumerService.setLocation(properties.getAcsUrl());
        spSsoDescriptor.getAssertionConsumerServices().add(assertionConsumerService);

        // Single Logout Service
        SingleLogoutService singleLogoutService = new SingleLogoutServiceBuilder().buildObject();
        singleLogoutService.setBinding("urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST");
        singleLogoutService.setLocation(properties.getSloUrl());
        spSsoDescriptor.getSingleLogoutServices().add(singleLogoutService);

        SingleLogoutService singleLogoutServiceRedirect = new SingleLogoutServiceBuilder().buildObject();
        singleLogoutServiceRedirect.setBinding("urn:oasis:names:tc:SAML:2.0:bindings:HTTP-Redirect");
        singleLogoutServiceRedirect.setLocation(properties.getSloUrl());
        spSsoDescriptor.getSingleLogoutServices().add(singleLogoutServiceRedirect);

        entityDescriptor.getRoleDescriptors().add(spSsoDescriptor);

        return entityDescriptor;
    }

    private void signSamlObject(org.opensaml.saml.common.SignableSAMLObject samlObject) throws MarshallingException, SignatureException, SecurityException {
        Signature signature = new SignatureBuilder().buildObject();
        signature.setSigningCredential(credentialManager.getSpCredential());
        signature.setSignatureAlgorithm(SignatureConstants.ALGO_ID_SIGNATURE_RSA_SHA256);
        signature.setCanonicalizationAlgorithm(SignatureConstants.ALGO_ID_C14N_EXCL_OMIT_COMMENTS);

        X509KeyInfoGeneratorFactory keyInfoGeneratorFactory = new X509KeyInfoGeneratorFactory();
        keyInfoGeneratorFactory.setEmitEntityCertificate(true);
        KeyInfoGenerator keyInfoGenerator = keyInfoGeneratorFactory.newInstance();
        signature.setKeyInfo(keyInfoGenerator.generate(credentialManager.getSpCredential()));

        samlObject.setSignature(signature);

        XMLObjectProviderRegistrySupport.getMarshallerFactory()
                .getMarshaller(samlObject)
                .marshall(samlObject);
        Signer.signObject(signature);
    }
}

