package com.example.samlsp.saml;

import com.example.samlsp.config.SamlSpProperties;
import com.example.samlsp.security.CredentialManager;
import net.shibboleth.utilities.java.support.xml.ParserPool;
import org.opensaml.core.xml.XMLObject;
import org.opensaml.core.xml.config.XMLObjectProviderRegistrySupport;
import org.opensaml.core.xml.io.UnmarshallerFactory;
import org.opensaml.core.xml.io.UnmarshallingException;
import org.opensaml.saml.saml2.core.*;
import org.opensaml.security.credential.Credential;
import org.opensaml.xmlsec.signature.Signature;
import org.opensaml.xmlsec.signature.support.SignatureException;
import org.opensaml.xmlsec.signature.support.SignatureValidator;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Component;
import org.w3c.dom.Document;
import org.w3c.dom.Element;

import java.io.ByteArrayInputStream;
import java.util.*;
import java.util.stream.Collectors;

@Component
public class SamlResponseProcessor {

    private static final Logger logger = LoggerFactory.getLogger(SamlResponseProcessor.class);

    private final SamlSpProperties properties;
    private final CredentialManager credentialManager;
    private final ParserPool parserPool;

    public SamlResponseProcessor(SamlSpProperties properties, CredentialManager credentialManager, ParserPool parserPool) {
        this.properties = properties;
        this.credentialManager = credentialManager;
        this.parserPool = parserPool;
    }

    public SamlAuthenticationResult processSamlResponse(String samlResponseBase64) throws Exception {
        byte[] decodedBytes = Base64.getDecoder().decode(samlResponseBase64);
        String samlResponseXml = new String(decodedBytes);

        logger.debug("Processing SAML Response");

        Response response = parseResponse(samlResponseXml);
        validateResponse(response);

        return extractAuthenticationResult(response);
    }

    private Response parseResponse(String responseXml) throws Exception {
        Document document = parserPool.parse(new ByteArrayInputStream(responseXml.getBytes()));
        Element element = document.getDocumentElement();

        UnmarshallerFactory unmarshallerFactory = XMLObjectProviderRegistrySupport.getUnmarshallerFactory();
        return (Response) unmarshallerFactory.getUnmarshaller(element).unmarshall(element);
    }

    public LogoutRequest parseLogoutRequest(String samlRequestBase64) throws Exception {
        byte[] decodedBytes = Base64.getDecoder().decode(samlRequestBase64);
        String xml = new String(decodedBytes);

        Document document = parserPool.parse(new ByteArrayInputStream(xml.getBytes()));
        Element element = document.getDocumentElement();

        UnmarshallerFactory unmarshallerFactory = XMLObjectProviderRegistrySupport.getUnmarshallerFactory();
        return (LogoutRequest) unmarshallerFactory.getUnmarshaller(element).unmarshall(element);
    }

    private void validateResponse(Response response) throws Exception {
        // Validate status
        StatusCode statusCode = response.getStatus().getStatusCode();
        if (!StatusCode.SUCCESS.equals(statusCode.getValue())) {
            throw new SamlValidationException("SAML Response status is not Success: " + statusCode.getValue());
        }

        // Validate destination
        if (response.getDestination() != null && !response.getDestination().equals(properties.getAcsUrl())) {
            throw new SamlValidationException("Invalid destination in SAML Response");
        }

        // Validate signature on response
        if (response.getSignature() != null) {
            validateSignature(response.getSignature());
        }

        // Validate assertions
        if (response.getAssertions().isEmpty()) {
            throw new SamlValidationException("No assertions found in SAML Response");
        }

        for (Assertion assertion : response.getAssertions()) {
            validateAssertion(assertion);
        }
    }

    private void validateAssertion(Assertion assertion) throws Exception {
        // Validate assertion signature if present
        if (assertion.getSignature() != null) {
            validateSignature(assertion.getSignature());
        } else if (properties.isWantAssertionsSigned()) {
            throw new SamlValidationException("Assertion is not signed but wantAssertionsSigned is true");
        }

        // Validate conditions
        Conditions conditions = assertion.getConditions();
        if (conditions != null) {
            org.joda.time.DateTime now = org.joda.time.DateTime.now();

            if (conditions.getNotBefore() != null && now.isBefore(conditions.getNotBefore())) {
                throw new SamlValidationException("Assertion is not yet valid (NotBefore)");
            }

            if (conditions.getNotOnOrAfter() != null && now.isAfter(conditions.getNotOnOrAfter())) {
                throw new SamlValidationException("Assertion has expired (NotOnOrAfter)");
            }

            // Validate audience restriction
            for (AudienceRestriction audienceRestriction : conditions.getAudienceRestrictions()) {
                boolean validAudience = audienceRestriction.getAudiences().stream()
                        .anyMatch(a -> properties.getEntityId().equals(a.getURI()));
                if (!validAudience) {
                    throw new SamlValidationException("SP entity ID is not in the audience restriction");
                }
            }
        }

        // Validate subject confirmation
        Subject subject = assertion.getSubject();
        if (subject != null) {
            for (SubjectConfirmation confirmation : subject.getSubjectConfirmations()) {
                SubjectConfirmationData confirmationData = confirmation.getSubjectConfirmationData();
                if (confirmationData != null) {
                    if (confirmationData.getNotOnOrAfter() != null &&
                            org.joda.time.DateTime.now().isAfter(confirmationData.getNotOnOrAfter())) {
                        throw new SamlValidationException("Subject confirmation data has expired");
                    }
                    if (confirmationData.getRecipient() != null &&
                            !confirmationData.getRecipient().equals(properties.getAcsUrl())) {
                        throw new SamlValidationException("Subject confirmation recipient does not match ACS URL");
                    }
                }
            }
        }
    }

    private void validateSignature(Signature signature) throws SamlValidationException {
        try {
            Credential idpCredential = credentialManager.getIdpCredential();
            if (idpCredential == null) {
                throw new SamlValidationException("IdP credential not configured for signature validation");
            }
            SignatureValidator.validate(signature, idpCredential);
            logger.debug("Signature validation successful");
        } catch (SignatureException e) {
            throw new SamlValidationException("Signature validation failed: " + e.getMessage(), e);
        }
    }

    private SamlAuthenticationResult extractAuthenticationResult(Response response) {
        Assertion assertion = response.getAssertions().get(0);

        String nameId = null;
        String nameIdFormat = null;
        if (assertion.getSubject() != null && assertion.getSubject().getNameID() != null) {
            nameId = assertion.getSubject().getNameID().getValue();
            nameIdFormat = assertion.getSubject().getNameID().getFormat();
        }

        String sessionIndex = null;
        if (!assertion.getAuthnStatements().isEmpty()) {
            sessionIndex = assertion.getAuthnStatements().get(0).getSessionIndex();
        }

        Map<String, List<String>> attributes = new HashMap<>();
        for (AttributeStatement attributeStatement : assertion.getAttributeStatements()) {
            for (Attribute attribute : attributeStatement.getAttributes()) {
                List<String> values = attribute.getAttributeValues().stream()
                        .map(XMLObject::getDOM)
                        .filter(Objects::nonNull)
                        .map(org.w3c.dom.Element::getTextContent)
                        .collect(Collectors.toList());
                attributes.put(attribute.getName(), values);
            }
        }

        return new SamlAuthenticationResult(nameId, nameIdFormat, sessionIndex, attributes, response.getID());
    }
}

// ==================== SAML Authentication Result ====================

package com.example.samlsp.saml;

import java.io.Serializable;
import java.util.List;
import java.util.Map;

public class SamlAuthenticationResult implements Serializable {

    private static final long serialVersionUID = 1L;

    private final String nameId;
    private final String nameIdFormat;
    private final String sessionIndex;
    private final Map<String, List<String>> attributes;
    private final String responseId;

    public SamlAuthenticationResult(String nameId, String nameIdFormat, String sessionIndex,
                                     Map<String, List<String>> attributes, String responseId) {
        this.nameId = nameId;
        this.nameIdFormat = nameIdFormat;
        this.sessionIndex = sessionIndex;
        this.attributes = attributes;
        this.responseId = responseId;
    }

    public String getNameId() { return nameId; }
    public String getNameIdFormat() { return nameIdFormat; }
    public String getSessionIndex() { return sessionIndex; }
    public Map<String, List<String>> getAttributes() { return attributes; }
    public String getResponseId() { return responseId; }

    public String getAttribute(String name) {
        List<String> values = attributes.get(name);
        return (values != null && !values.isEmpty()) ? values.get(0) : null;
    }

    @Override
    public String toString() {
        return "SamlAuthenticationResult{" +
                "nameId='" + nameId + '\'' +
                ", sessionIndex='" + sessionIndex + '\'' +
                ", attributes=" + attributes +
                '}';
    }
}

