// ==================== SAML Encoding Utility ====================

package com.example.samlsp.saml;

import net.shibboleth.utilities.java.support.xml.SerializeSupport;
import org.opensaml.core.xml.XMLObject;
import org.opensaml.core.xml.config.XMLObjectProviderRegistrySupport;
import org.opensaml.core.xml.io.Marshaller;
import org.opensaml.core.xml.io.MarshallingException;
import org.springframework.stereotype.Component;
import org.w3c.dom.Element;

import java.io.ByteArrayOutputStream;
import java.net.URLEncoder;
import java.nio.charset.StandardCharsets;
import java.util.Base64;
import java.util.zip.Deflater;
import java.util.zip.DeflaterOutputStream;

@Component
public class SamlEncodingUtils {

    public String encodeForPost(XMLObject xmlObject) throws MarshallingException {
        String xml = marshalToXml(xmlObject);
        return Base64.getEncoder().encodeToString(xml.getBytes(StandardCharsets.UTF_8));
    }

    public String encodeForRedirect(XMLObject xmlObject) throws Exception {
        String xml = marshalToXml(xmlObject);

        ByteArrayOutputStream bytesOut = new ByteArrayOutputStream();
        Deflater deflater = new Deflater(Deflater.DEFLATED, true);
        DeflaterOutputStream deflaterStream = new DeflaterOutputStream(bytesOut, deflater);
        deflaterStream.write(xml.getBytes(StandardCharsets.UTF_8));
        deflaterStream.finish();

        String base64 = Base64.getEncoder().encodeToString(bytesOut.toByteArray());
        return URLEncoder.encode(base64, StandardCharsets.UTF_8.name());
    }

    public String marshalToXml(XMLObject xmlObject) throws MarshallingException {
        Marshaller marshaller = XMLObjectProviderRegistrySupport.getMarshallerFactory()
                .getMarshaller(xmlObject);
        Element element = marshaller.marshall(xmlObject);
        return SerializeSupport.nodeToString(element);
    }
}

