package com.example.samlsp.security;

import com.example.samlsp.saml.SamlAuthenticationResult;
import org.springframework.security.authentication.AbstractAuthenticationToken;
import org.springframework.security.core.GrantedAuthority;

import java.util.Collection;

public class SamlAuthenticationToken extends AbstractAuthenticationToken {

    private static final long serialVersionUID = 1L;

    private final String principal;
    private final SamlAuthenticationResult samlResult;

    public SamlAuthenticationToken(String principal, SamlAuthenticationResult samlResult,
                                    Collection<? extends GrantedAuthority> authorities) {
        super(authorities);
        this.principal = principal;
        this.samlResult = samlResult;
        setAuthenticated(true);
    }

    @Override
    public Object getCredentials() {
        return samlResult;
    }

    @Override
    public Object getPrincipal() {
        return principal;
    }

    public SamlAuthenticationResult getSamlResult() {
        return samlResult;
    }
}

// ==================== SAML User Details ====================

package com.example.samlsp.security;

import com.example.samlsp.saml.SamlAuthenticationResult;

import java.io.Serializable;
import java.util.List;
import java.util.Map;

public class SamlUserDetails implements Serializable {

    private static final long serialVersionUID = 1L;

    private String nameId;
    private String email;
    private String firstName;
    private String lastName;
    private String displayName;
    private String sessionIndex;
    private Map<String, List<String>> attributes;

    public static SamlUserDetails fromAuthResult(SamlAuthenticationResult result) {
        SamlUserDetails details = new SamlUserDetails();
        details.nameId = result.getNameId();
        details.sessionIndex = result.getSessionIndex();
        details.attributes = result.getAttributes();

        details.email = result.getAttribute("email");
        if (details.email == null) {
            details.email = result.getAttribute("http://schemas.xmlsoap.org/ws/2005/05/identity/claims/emailaddress");
        }
        if (details.email == null) {
            details.email = result.getNameId();
        }

        details.firstName = result.getAttribute("firstName");
        if (details.firstName == null) {
            details.firstName = result.getAttribute("http://schemas.xmlsoap.org/ws/2005/05/identity/claims/givenname");
        }

        details.lastName = result.getAttribute("lastName");
        if (details.lastName == null) {
            details.lastName = result.getAttribute("http://schemas.xmlsoap.org/ws/2005/05/identity/claims/surname");
        }

        details.displayName = result.getAttribute("displayName");
        if (details.displayName == null) {
            details.displayName = result.getAttribute("http://schemas.xmlsoap.org/ws/2005/05/identity/claims/name");
        }

        return details;
    }

    public String getNameId() { return nameId; }
    public String getEmail() { return email; }
    public String getFirstName() { return firstName; }
    public String getLastName() { return lastName; }
    public String getDisplayName() { return displayName; }
    public String getSessionIndex() { return sessionIndex; }
    public Map<String, List<String>> getAttributes() { return attributes; }
}

// ==================== SAML Session Manager ====================

package com.example.samlsp.security;

import com.example.samlsp.saml.SamlAuthenticationResult;
import org.springframework.stereotype.Component;

import java.util.concurrent.ConcurrentHashMap;
import java.util.Map;

@Component
public class SamlSessionManager {

    private final Map<String, SamlAuthenticationResult> sessionStore = new ConcurrentHashMap<>();
    private final Map<String, String> nameIdToSessionId = new ConcurrentHashMap<>();

    public void storeSession(String httpSessionId, SamlAuthenticationResult authResult) {
        sessionStore.put(httpSessionId, authResult);
        if (authResult.getNameId() != null) {
            nameIdToSessionId.put(authResult.getNameId(), httpSessionId);
        }
    }

    public SamlAuthenticationResult getSession(String httpSessionId) {
        return sessionStore.get(httpSessionId);
    }

    public void removeSession(String httpSessionId) {
        SamlAuthenticationResult result = sessionStore.remove(httpSessionId);
        if (result != null && result.getNameId() != null) {
            nameIdToSessionId.remove(result.getNameId());
        }
    }

    public String getSessionIdByNameId(String nameId) {
        return nameIdToSessionId.get(nameId);
    }

    public void removeSessionByNameId(String nameId) {
        String sessionId = nameIdToSessionId.remove(nameId);
        if (sessionId != null) {
            sessionStore.remove(sessionId);
        }
    }
}

// ==================== SAML Relay State Manager ====================

package com.example.samlsp.security;

import org.springframework.stereotype.Component;

import java.util.UUID;
import java.util.concurrent.ConcurrentHashMap;
import java.util.Map;

@Component
public class RelayStateManager {

    private final Map<String, String> relayStateStore = new ConcurrentHashMap<>();

    public String generateRelayState(String targetUrl) {
        String relayState = UUID.randomUUID().toString();
        relayStateStore.put(relayState, targetUrl);
        return relayState;
    }

    public String getTargetUrl(String relayState) {
        return relayStateStore.remove(relayState);
    }
}

// ==================== Security Configuration ====================

package com.example.samlsp.config;

import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.web.SecurityFilterChain;

@Configuration
@EnableWebSecurity
public class SecurityConfig {

    @Bean
    public SecurityFilterChain filterChain(HttpSecurity http) throws Exception {
        http
                .csrf(csrf -> csrf
                        .ignoringAntMatchers("/saml/**")
                )
                .authorizeRequests(authz -> authz
                        .antMatchers("/saml/**", "/login", "/error", "/health").permitAll()
                        .anyRequest().authenticated()
                )
                .formLogin(form -> form.disable())
                .logout(logout -> logout
                        .logoutUrl("/logout")
                        .logoutSuccessUrl("/saml/slo/init")
                )
                .exceptionHandling(ex -> ex
                        .authenticationEntryPoint((request, response, authException) -> {
                            response.sendRedirect("/saml/login");
                        })
                );

        return http.build();
    }
}

// ==================== SAML Controller ====================

package com.example.samlsp.controller;

import com.example.samlsp.config.SamlSpProperties;
import com.example.samlsp.saml.*;
import com.example.samlsp.security.*;
import org.opensaml.saml.saml2.core.AuthnRequest;
import org.opensaml.saml.saml2.core.LogoutRequest;
import org.opensaml.saml.saml2.core.LogoutResponse;
import org.opensaml.saml.saml2.metadata.EntityDescriptor;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.http.MediaType;
import org.springframework.security.core.authority.SimpleGrantedAuthority;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.*;

import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import javax.servlet.http.HttpSession;
import java.util.Collections;

@Controller
@RequestMapping("/saml")
public class SamlController {

    private static final Logger logger = LoggerFactory.getLogger(SamlController.class);

    private final SamlSpProperties properties;
    private final SamlMessageBuilder messageBuilder;
    private final SamlResponseProcessor responseProcessor;
    private final SamlEncodingUtils encodingUtils;
    private final SamlSessionManager sessionManager;
    private final RelayStateManager relayStateManager;

    public SamlController(SamlSpProperties properties,
                          SamlMessageBuilder messageBuilder,
                          SamlResponseProcessor responseProcessor,
                          SamlEncodingUtils encodingUtils,
                          SamlSessionManager sessionManager,
                          RelayStateManager relayStateManager) {
        this.properties = properties;
        this.messageBuilder = messageBuilder;
        this.responseProcessor = responseProcessor;
        this.encodingUtils = encodingUtils;
        this.sessionManager = sessionManager;
        this.relayStateManager = relayStateManager;
    }

    @GetMapping("/metadata")
    @ResponseBody
    public String metadata() throws Exception {
        EntityDescriptor spMetadata = messageBuilder.buildSpMetadata();
        return encodingUtils.marshalToXml(spMetadata);
    }

    @GetMapping("/login")
    public String initiateLogin(@RequestParam(value = "returnTo", required = false, defaultValue = "/") String returnTo,
                                 Model model) throws Exception {
        logger.info("Initiating SAML SSO login");

        AuthnRequest authnRequest = messageBuilder.buildAuthnRequest();
        String samlRequest = encodingUtils.encodeForPost(authnRequest);
        String relayState = relayStateManager.generateRelayState(returnTo);

        model.addAttribute("samlRequest", samlRequest);
        model.addAttribute("relayState", relayState);
        model.addAttribute("idpSsoUrl", properties.getIdpSsoUrl());

        return "saml-post-form";
    }

    @GetMapping("/login/redirect")
    public void initiateLoginRedirect(@RequestParam(value = "returnTo", required = false, defaultValue = "/") String returnTo,
                                       HttpServletResponse response) throws Exception {
        logger.info("Initiating SAML SSO login via redirect");

        AuthnRequest authnRequest = messageBuilder.buildAuthnRequest();
        String samlRequest = encodingUtils.encodeForRedirect(authnRequest);
        String relayState = relayStateManager.generateRelayState(returnTo);

        String redirectUrl = properties.getIdpSsoUrl() +
                "?SAMLRequest=" + samlRequest +
                "&RelayState=" + relayState;

        response.sendRedirect(redirectUrl);
    }

    @PostMapping("/acs")
    public String assertionConsumerService(@RequestParam("SAMLResponse") String samlResponse,
                                            @RequestParam(value = "RelayState", required = false) String relayState,
                                            HttpServletRequest request,
                                            HttpServletResponse response) throws Exception {
        logger.info("Received SAML Response at ACS endpoint");

        try {
            SamlAuthenticationResult authResult = responseProcessor.processSamlResponse(samlResponse);
            logger.info("SAML authentication successful for user: {}", authResult.getNameId());

            // Create authentication token
            SamlAuthenticationToken authToken = new SamlAuthenticationToken(
                    authResult.getNameId(),
                    authResult,
                    Collections.singletonList(new SimpleGrantedAuthority("ROLE_USER"))
            );

            SecurityContextHolder.getContext().setAuthentication(authToken);

            // Store session
            HttpSession session = request.getSession(true);
            sessionManager.storeSession(session.getId(), authResult);
            session.setAttribute("SAML_USER", SamlUserDetails.fromAuthResult(authResult));

            // Redirect to target URL
            String targetUrl = "/";
            if (relayState != null) {
                String url = relayStateManager.getTargetUrl(relayState);
                if (url != null) {
                    targetUrl = url;
                }
            }

            return "redirect:" + targetUrl;

        } catch (SamlValidationException e) {
            logger.error("SAML Response validation failed: {}", e.getMessage());
            return "redirect:/login?error=saml_validation_failed";
        } catch (Exception e) {
            logger.error("Error processing SAML Response", e);
            return "redirect:/login?error=saml_processing_error";
        }
    }

    @GetMapping("/slo/init")
    public String initiateSingleLogout(HttpServletRequest request, Model model) throws Exception {
        logger.info("Initiating Single Logout");

        HttpSession session = request.getSession(false);
        if (session == null) {
            return "redirect:/login";
        }

        SamlUserDetails userDetails = (SamlUserDetails) session.getAttribute("SAML_USER");
        if (userDetails == null) {
            session.invalidate();
            SecurityContextHolder.clearContext();
            return "redirect:/login";
        }

        LogoutRequest logoutRequest = messageBuilder.buildLogoutRequest(
                userDetails.getNameId(),
                userDetails.getSessionIndex()
        );

        String samlRequest = encodingUtils.encodeForPost(logoutRequest);

        model.addAttribute("samlRequest", samlRequest);
        model.addAttribute("idpSloUrl", properties.getIdpSloUrl());
        model.addAttribute("relayState", "logout");

        // Clean up local session
        sessionManager.removeSession(session.getId());
        session.invalidate();
        SecurityContextHolder.clearContext();

        return "saml-logout-form";
    }

    @PostMapping("/slo")
    public String processSingleLogout(@RequestParam(value = "SAMLRequest", required = false) String samlRequest,
                                       @RequestParam(value = "SAMLResponse", required = false) String samlLogoutResponse,
                                       @RequestParam(value = "RelayState", required = false) String relayState,
                                       HttpServletRequest request,
                                       Model model) throws Exception {

        if (samlRequest != null) {
            // IdP-initiated SLO
            logger.info("Processing IdP-initiated Single Logout request");

            LogoutRequest logoutRequest = responseProcessor.parseLogoutRequest(samlRequest);
            String nameId = logoutRequest.getNameID().getValue();

            // Remove session
            sessionManager.removeSessionByNameId(nameId);

            HttpSession session = request.getSession(false);
            if (session != null) {
                session.invalidate();
            }
            SecurityContextHolder.clearContext();

            // Send LogoutResponse back to IdP
            LogoutResponse logoutResponse = messageBuilder.buildLogoutResponse(logoutRequest.getID());
            String encodedResponse = encodingUtils.encodeForPost(logoutResponse);

            model.addAttribute("samlResponse", encodedResponse);
            model.addAttribute("idpSloUrl", properties.getIdpSloUrl());
            model.addAttribute("relayState", relayState);

            return "saml-slo-response-form";

        } else if (samlLogoutResponse != null) {
            // Response to SP-initiated SLO
            logger.info("Received LogoutResponse from IdP");

            HttpSession session = request.getSession(false);
            if (session != null) {
                sessionManager.removeSession(session.getId());
                session.invalidate();
            }
            SecurityContextHolder.clearContext();

            return "redirect:/login?logout=success";
        }

        return "redirect:/login";
    }

    @GetMapping("/slo")
    public String processSingleLogoutGet(@RequestParam(value = "SAMLRequest", required = false) String samlRequest,
                                          @RequestParam(value = "SAMLResponse", required = false) String samlLogoutResponse,
                                          @RequestParam(value = "RelayState", required = false) String relayState,
                                          HttpServletRequest request,
                                          Model model) throws Exception {
        return processSingleLogout(samlRequest, samlLogoutResponse, relayState, request, model);
    }
}

// ==================== Application Controller ====================

package com.example.samlsp.controller;

import com.example.samlsp.security.SamlAuthenticationToken;
import com.example.samlsp.security.SamlUserDetails;
import org.springframework.security.core.Authentication;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.ResponseBody;

import javax.servlet.http.HttpSession;
import java.util.HashMap;
import java.util.Map;

@Controller
public class ApplicationController {

    @GetMapping("/")
    public String home(Model model, HttpSession session) {
        SamlUserDetails userDetails = (SamlUserDetails) session.getAttribute("SAML_USER");
        if (userDetails != null) {
            model.addAttribute("user", userDetails);
        }
        return "home";
    }

    @GetMapping("/profile")
    @ResponseBody
    public Map<String, Object> profile(HttpSession session) {
        Authentication auth = SecurityContextHolder.getContext().getAuthentication();
        Map<String, Object> profile = new HashMap<>();

        if (auth instanceof SamlAuthenticationToken) {
            SamlAuthenticationToken samlAuth = (SamlAuthenticationToken) auth;
            SamlUserDetails userDetails = (SamlUserDetails) session.getAttribute("SAML_USER");

            profile.put("authenticated", true);
            profile.put("nameId", samlAuth.getPrincipal());

            if (userDetails != null) {
                profile.put("email", userDetails.getEmail());
                profile.put("firstName", userDetails.getFirstName());
                profile.put("lastName", userDetails.getLastName());
                profile.put("displayName", userDetails.getDisplayName());
                profile.put("attributes", userDetails.getAttributes());
            }
        } else {
            profile.put("authenticated", false);
        }

        return profile;
    }

    @GetMapping("/health")
    @ResponseBody
    public Map<String, String> health() {
        Map<String, String> health = new HashMap<>();
        health.put("status", "UP");
        health.put("service", "SAML Service Provider");
        return health;
    }
}

